function Inbox({ messages }) {
  const { div, span, h3, p } = tags;
  const [selected, setSelected] = createSignal(0);

  return div({ class: css('_grid _gc1 _lg:gc3 _gap0 _h[calc(100vh-120px)] _overflow[hidden] _b1 _bcborder _r4') },
    div({ class: css('_flex _col _borderR _overflow[hidden]') },
      div({ class: css('_p3 _borderB') },
        Input({ placeholder: 'Search messages...', class: css('_wfull') })
      ),
      div({ class: css('_flex1 _overflow[auto]') },
        ...messages.map((msg, i) =>
          div({ class: css(`_flex _gap3 _p3 _borderB _cursor[pointer] ${i === selected() ? '_bgprimary/10' : ''}`), onclick: () => setSelected(i) },
            Avatar({ name: msg.from, size: 'sm' }),
            div({ class: css('_flex _col _flex1 _minW0') },
              div({ class: css('_flex _aic _jcsb') },
                span({ class: css(`_textsm ${msg.unread ? '_bold' : ''}`) }, msg.from),
                span({ class: css('_textxs _fgmuted') }, msg.time)
              ),
              span({ class: css('_textsm _bold _truncate') }, msg.subject),
              span({ class: css('_textxs _fgmuted _truncate') }, msg.preview)
            ),
            msg.unread ? div({ class: css('_w[8px] _h[8px] _rfull _bgprimary _flexShrink0 _mt2') }) : null
          )
        )
      )
    ),
    div({ class: css('_span2 _flex _col _overflow[hidden]') },
      div({ class: css('_flex _aic _jcsb _p4 _borderB') },
        div({ class: css('_flex _col') },
          h3({ class: css('_heading5') }, messages[selected()]?.subject),
          span({ class: css('_textsm _fgmuted') }, `From: ${messages[selected()]?.from}`)
        ),
        div({ class: css('_flex _gap2') },
          Button({ variant: 'ghost', size: 'sm' }, icon('reply', { size: '1em' })),
          Button({ variant: 'ghost', size: 'sm' }, icon('archive', { size: '1em' })),
          Button({ variant: 'ghost', size: 'sm' }, icon('trash', { size: '1em' }))
        )
      ),
      div({ class: css('_flex1 _overflow[auto] _p4') },
        p({ class: css('_body _fgfg') }, messages[selected()]?.body)
      )
    )
  );
}
